const providerFileName = String($json.name || '').trim();
const providerFileId = String($json.id || '').trim();
const defaultHouseholdId = String($env.STATEMENT_HOUSEHOLD_ID || '').trim();
const routingRules = JSON.parse($env.STATEMENT_FILE_ROUTING_JSON || '[]');

if (!providerFileName) {
  throw new Error('Drive trigger payload is missing the file name.');
}

if (!providerFileId) {
  throw new Error('Drive trigger payload is missing the file id.');
}

if (!Array.isArray(routingRules) || routingRules.length === 0) {
  throw new Error('STATEMENT_FILE_ROUTING_JSON must define at least one routing rule.');
}

const matchedRule = routingRules.find((rule) => {
  const pattern = String(rule?.fileNamePattern || '').trim();

  if (!pattern) {
    return false;
  }

  return new RegExp(pattern, 'i').test(providerFileName);
});

if (!matchedRule) {
  throw new Error(`No statement routing rule matched ${providerFileName}.`);
}

const householdId = String(matchedRule.householdId || defaultHouseholdId || '').trim();
const parserProfileName = String(matchedRule.parserProfileName || '').trim();

if (!householdId) {
  throw new Error(`No household id is configured for ${providerFileName}.`);
}

if (!parserProfileName) {
  throw new Error(`No parser profile is configured for ${providerFileName}.`);
}

return [{
  json: {
    ...$json,
    bankName: matchedRule.bankName || null,
    cardName: matchedRule.cardName || null,
    householdId,
    parserProfileName,
    providerFileId,
    providerFileName,
    statementPasswordKey: matchedRule.statementPasswordKey || null,
  },
}];
